    $lines.Add('            const isOpen = !sidebar.classList.contains(''-translate-x-full'');')
    $lines.Add('            if (isOpen) {')
    $lines.Add('                sidebar.classList.add(''-translate-x-full'');')
    $lines.Add('                overlay.classList.add(''hidden'');')
    $lines.Add('            } else {')
    $lines.Add('                sidebar.classList.remove(''-translate-x-full'');')
    $lines.Add('                overlay.classList.remove(''hidden'');')
    $lines.Add('            }')
    $lines.Add('        }')
    $lines.Add('        function toggleSubMenu(id, header) {')
    $lines.Add('            const content = document.getElementById(id);')
    $lines.Add('            if (!content) return;')
    $lines.Add('            const isOpen = content.classList.contains(''open'');')
    $lines.Add('            document.querySelectorAll(''.menu-content.open'').forEach(menu => {')
    $lines.Add('                if (menu.id !== id) {')
    $lines.Add('                    menu.classList.remove(''open'');')
    $lines.Add('                    const parent = menu.previousElementSibling;')
    $lines.Add('                    if (parent && parent.classList.contains(''menu-parent'')) parent.classList.remove(''active'');')
    $lines.Add('                }')
    $lines.Add('            });')
    $lines.Add('            if (isOpen) { content.classList.remove(''open''); header.classList.remove(''active''); }')
    $lines.Add('            else { content.classList.add(''open''); header.classList.add(''active''); }')
    $lines.Add('        }')
