$pages = @(
    @{file = 'index.html'; title = 'Inicio'; icon = 'home'; active = 'inicio'; badge = 'Bienvenido al Museo'; h1a = 'Museo de'; h1b = 'Tanques'; desc = '[BORRADOR] Pagina de inicio del Museo de Tanques. Aqui ira la descripcion general, bienvenida y accesos rapidos a las secciones principales.' },
    @{file = 'tour.html'; title = 'Tour Virtual'; icon = '360'; active = 'tour'; badge = 'Experiencia Inmersiva'; h1a = 'Tour'; h1b = 'Virtual 360'; desc = '[BORRADOR] Recorre de forma inmersiva el museo con nuestro tour virtual 360 grados desde cualquier dispositivo.' },
    @{file = 'museum.html'; title = 'Museo'; icon = 'account_balance'; active = 'museo'; badge = 'Nuestra Identidad'; h1a = 'El'; h1b = 'Museo'; desc = '[BORRADOR] Historia, mision y vision del Museo de Tanques. Conoce el equipo y proyectos en curso.' },
    @{file = 'galeria.html'; title = 'Galeria'; icon = 'imagesmode'; active = 'galeria'; badge = 'Coleccion Multimedia'; h1a = 'Galeria de'; h1b = 'Blindados'; desc = '[BORRADOR] Explora fotografias, videos, audios y modelos 3D de nuestra coleccion de vehiculos blindados.' },
    @{file = 'contactos.html'; title = 'Contactos'; icon = 'contact_support'; active = 'contactos'; badge = 'Ponte en Contacto'; h1a = 'Contacta'; h1b = 'con Nosotros'; desc = '[BORRADOR] Informacion de contacto, visitas guiadas y sugerencias del publico.' },
    @{file = 'servicios.html'; title = 'Servicios'; icon = 'construction'; active = 'servicios'; badge = 'Para el Visitante'; h1a = 'Nuestros'; h1b = 'Servicios'; desc = '[BORRADOR] Servicios disponibles: cafeteria, guias especializados, tienda oficial, estacionamiento y mas.' }
)

foreach ($p in $pages) {
    $html = Get-HTML $p.title $p.icon $p.badge $p.h1a $p.h1b $p.desc $p.active
    $filePath = Join-Path $dir $p.file
    [System.IO.File]::WriteAllText($filePath, $html, [System.Text.Encoding]::UTF8)
    Write-Host "CREADO: $($p.file)" -ForegroundColor Green
}

Write-Host ''
Write-Host 'Todos los archivos generados correctamente.' -ForegroundColor Cyan
